import React, { useEffect, useState } from 'react';
import axios from 'axios';

const statusColors = {
  'pending': 'secondary',
  'in-progress': 'warning',
  'resolved': 'success'
};

const AdminDashboard = () => {

    const [complaints, setComplaints] = useState({ pending: [], inProgress: [], resolved: [] });
    const [staffList, setStaffList] = useState([]);
    const [search, setSearch] = useState('');
    const [notesEdit, setNotesEdit] = useState({});
    const [statusEdit, setStatusEdit] = useState({});
    const [activeTab, setActiveTab] = useState('pending');
    const [selectedAssign, setSelectedAssign] = useState({});

    useEffect(() => {
        fetchComplaints();
        fetchStaff();
    }, []);

    const fetchComplaints = async () => {
        const res = await axios.get('http://localhost:5001/api/complaints', {
            headers: { Authorization: `Bearer ${localStorage.getItem('token')}` }
        });
        setComplaints(res.data);
    };

    const fetchStaff = async () => {
        const res = await axios.get('http://localhost:5001/api/auth/staff', {
            headers: { Authorization: `Bearer ${localStorage.getItem('token')}` }
        });
        setStaffList(res.data);
    };

    // ✅ Worker type dropdown handler
    const handleAssignType = (id, value) => {
        setSelectedAssign(prev => ({
            ...prev,
            [id]: value
        }));
    };

    const handleStatusChange = (id, value) => {
        setStatusEdit(prev => ({ ...prev, [id]: value }));
    };

    const handleNotesChange = (id, value) => {
        setNotesEdit(prev => ({ ...prev, [id]: value }));
    };

    const handleStatusUpdate = async (id) => {
        await axios.put(
            `http://localhost:5001/api/complaints/${id}/status`,
            {
                status: statusEdit[id],
                resolutionNotes: notesEdit[id]
            },
            {
                headers: { Authorization: `Bearer ${localStorage.getItem('token')}` }
            }
        );
        fetchComplaints();
    };

    const filterData = (list) =>
        list.filter(c =>
            c.title.toLowerCase().includes(search.toLowerCase()) ||
            c.status.toLowerCase().includes(search.toLowerCase())
        );

    const renderRows = (data) => data.map(c => (
        <React.Fragment key={c._id}>
            <tr>
                <td><strong>{c.title}</strong></td>

                <td>
                    <span className={`badge bg-${statusColors[c.status]}`}>
                        {c.status}
                    </span>
                </td>

                <td>{c.category}</td>
                <td>{c.dueInDays}</td>
                <td>{c.raisedBy?.email}</td>

                <td>
                    {c.assignedTo?.email || <span className="text-muted">Unassigned</span>}
                </td>

                {/* ✅ YOUR NEW DROPDOWN */}
                <td>
                    <select
                        className="form-select"
                        value={selectedAssign[c._id] || ''}
                        onChange={(e) => handleAssignType(c._id, e.target.value)}
                    >
                        <option value="">Select Worker Type</option>
                        <option value="Mechanic">Mechanic</option>
                        <option value="Lift Mechanic">Lift Mechanic</option>
                        <option value="Plumber">Plumber</option>
                        <option value="Electrician">Electrician</option>
                    </select>
                </td>

                {/* ✅ STATUS UPDATE (NOT REMOVED) */}
                <td>
                    <div className="d-flex gap-2">
                        <select
                            className="form-select"
                            value={statusEdit[c._id] || c.status}
                            onChange={(e) => handleStatusChange(c._id, e.target.value)}
                        >
                            <option value="pending">Pending</option>
                            <option value="in-progress">In Progress</option>
                            <option value="resolved">Resolved</option>
                        </select>

                        <button
                            className="btn btn-sm btn-primary"
                            onClick={() => handleStatusUpdate(c._id)}
                        >
                            Update
                        </button>
                    </div>
                </td>

                {/* ✅ RESOLUTION NOTES (NOT REMOVED) */}
                <td>
                    <input
                        type="text"
                        className="form-control"
                        value={notesEdit[c._id] ?? c.resolutionNotes ?? ''}
                        onChange={(e) => handleNotesChange(c._id, e.target.value)}
                        placeholder="Add notes"
                    />
                </td>
            </tr>
        </React.Fragment>
    ));

    return (
        <div className="container py-4">
            <h2>Admin Complaint Dashboard</h2>

            <input
                type="text"
                className="form-control mb-3"
                placeholder="Search"
                value={search}
                onChange={(e) => setSearch(e.target.value)}
            />

            <div className="mb-3">
                <button onClick={() => setActiveTab('pending')} className="btn btn-primary">Pending</button>
                <button onClick={() => setActiveTab('inProgress')} className="btn btn-warning mx-2">In Progress</button>
                <button onClick={() => setActiveTab('resolved')} className="btn btn-success">Resolved</button>
            </div>

            <table className="table table-bordered">
                <thead>
                    <tr>
                        <th>Title</th>
                        <th>Status</th>
                        <th>Category</th>
                        <th>Due</th>
                        <th>User</th>
                        <th>Assigned</th>
                        <th>Assign</th>
                        <th>Status Update</th>
                        <th>Notes</th>
                    </tr>
                </thead>

                <tbody>
                    {activeTab === 'pending' && renderRows(filterData(complaints.pending))}
                    {activeTab === 'inProgress' && renderRows(filterData(complaints.inProgress))}
                    {activeTab === 'resolved' && renderRows(filterData(complaints.resolved))}
                </tbody>
            </table>
        </div>
    );
};

export default AdminDashboard;
